mapper.select:
select count(id) as totalCount, sum(success_count) as successCount, sum(fail_count) as failCount, sum(error_count + timeout_count) as errorCount, CASE WHEN SUM(total_count) = 0 THEN 0 ELSE (SUM(success_count) / SUM(total_count)) * 100 END AS passRate, CASE WHEN SUM(total_count) = 0 THEN 0 ELSE ROUND(SUM(total_time) / SUM(total_count)) END AS totalTime from run_record
project_id = #{projectId}
and run_type = #{runType}
and status = #{status}
